成品如下
代码如下




Shader "Custom/PostProcessing"
{
    Properties
    {
        _MainTex ("MainTex", 2D) = "white" {}
        _pw("Pixel Width", float) = 64
        _ph("Pixel Height", float) = 64
    }
    SubShader
    {
        Tags { "RenderType"="Opaque" }

        LOD 200

        Cull Off ZWrite Off ZTest Always

